import React, { useState } from 'react';
import Logo from './Logo.png'; 
import Menu, { Lunch } from './Menu'; 

function App() {
  const gold = '#D4AF37';
  const [activeCategory, setActiveCategory] = useState('Small Chops');
  const fancyFont = "'Playfair Display', 'Georgia', serif";

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', margin: 0, padding: 0, fontFamily: 'Arial, sans-serif' }}>
      
      {/* 1. THE GOLDEN NAVIGATION */}
      <nav style={{ 
        display: 'flex', 
        flexDirection: 'column', 
        alignItems: 'center', 
        padding: '50px 20px', 
        backgroundColor: '#000', 
        borderBottom: '1px solid #111'
      }}>
        <img src={Logo} alt="Àmí by T" style={{ 
          height: '140px', 
          width: 'auto',
          marginBottom: '40px',
          filter: 'contrast(130%) brightness(120%)',
          mixBlendMode: 'screen'
        }} />

        <div style={{ display: 'flex', gap: '50px' }}>
          {['Small Chops', 'Office Lunch', 'Wigs', 'About Us'].map((item) => (
            <button 
              key={item} 
              onClick={() => setActiveCategory(item)}
              style={{ 
                background: 'none',
                border: 'none',
                color: gold, 
                fontSize: '0.9rem', 
                fontWeight: '400',
                fontFamily: fancyFont,
                letterSpacing: '2px',
                textTransform: 'uppercase',
                cursor: 'pointer',
                paddingBottom: '10px',
                borderBottom: activeCategory === item ? `1.5px solid ${gold}` : '1.5px solid transparent',
                opacity: activeCategory === item ? 1 : 0.35,
                transition: '0.4s ease'
              }}
            >
              {item}
            </button>
          ))}
        </div>
      </nav>

      {/* 2. THE STAGE */}
      <main style={{ padding: '60px 20px', maxWidth: '1200px', margin: '0 auto' }}>
        
        {activeCategory === 'Small Chops' && (
          <div>
            <h2 style={{ 
              color: gold, 
              textAlign: 'center', 
              fontSize: '3rem', 
              marginBottom: '50px',
              fontWeight: '400',
              fontFamily: fancyFont,
              letterSpacing: '3px',
              fontStyle: 'italic'
            }}>
              Small Chops Curates
            </h2>
            <Menu />
          </div>
        )}

        {activeCategory === 'Office Lunch' && (
          <div>
            <h2 style={{ 
              color: gold, 
              textAlign: 'center', 
              fontSize: '3rem', 
              marginBottom: '50px',
              fontWeight: '400',
              fontFamily: fancyFont,
              letterSpacing: '3px',
              fontStyle: 'italic'
            }}>
              The Office Lunch
            </h2>
            <Lunch />
          </div>
        )}

        {activeCategory === 'Wigs' && (
          <div style={{ textAlign: 'center', padding: '100px 20px' }}>
            <h2 style={{ color: gold, fontSize: '3rem', fontFamily: fancyFont, fontStyle: 'italic' }}>
              The Hair Edit
            </h2>
            <p style={{ color: gold, opacity: 0.5, marginTop: '20px', letterSpacing: '2px' }}>COMING SOON</p>
          </div>
        )}

        {activeCategory === 'About Us' && (
          <div style={{ textAlign: 'center', padding: '80px 20px', color: gold }}>
            <h2 style={{ fontSize: '3rem', fontFamily: fancyFont, fontStyle: 'italic' }}>Our Story</h2>
            <p style={{ maxWidth: '700px', margin: '40px auto', lineHeight: '2', opacity: 0.8, fontSize: '1.1rem', fontWeight: '300' }}>
              Àmí by T is a Lagos-born boutique catering experience. We believe that food should not just be eaten, it should be experienced.
            </p>
          </div>
        )}
      </main>

      {/* 3. FOOTER */}
      <footer style={{ textAlign: 'center', padding: '100px 40px', color: '#1a1a1a' }}>
        <p style={{ letterSpacing: '6px', color: gold, opacity: 0.2 }}>ÀMÍ BY T | EST. 2026</p>
      </footer>

    </div>
  );
}

export default App;
